const express = require('express');
const jwt = require('jsonwebtoken');
const axios = require('axios');
const app = express();

// Mock JWKS endpoint - in production, this should be a real JWKS endpoint
const jwksEndpoint = 'https://your-tenant.b2clogin.com/your-tenant.onmicrosoft.com/discovery/keys';

// Cache for JWKS
let jwksCache = null;
let jwksCacheExpiry = 0;

// Middleware to validate JWT tokens
const authenticateToken = async (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Access token required' });
  }

  try {
    // Get JWKS
    const jwks = await getJWKS();
    
    // Verify token
    const decoded = jwt.verify(token, jwks, {
      algorithms: ['RS256'],
      audience: process.env.AUDIENCE,
      issuer: process.env.ISSUER
    });
    
    req.user = decoded;
    next();
  } catch (error) {
    console.error('Token validation error:', error);
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
};

// Get JWKS with caching
async function getJWKS() {
  const now = Date.now();
  
  if (jwksCache && now < jwksCacheExpiry) {
    return jwksCache;
  }
  
  try {
    const response = await axios.get(jwksEndpoint, {
      timeout: 5000,
      headers: {
        'Accept': 'application/json'
      }
    });
    
    jwksCache = response.data;
    jwksCacheExpiry = now + 300000; // Cache for 5 minutes
    
    return response.data;
  } catch (error) {
    throw new Error('Failed to fetch JWKS');
  }
}

